// Parse the customer-portal DID change request.
const raw = $input.first().json;
const body = raw.body || raw;
const out = {
  stripe_subscription_id: body.stripe_subscription_id || body.subscription_id || '',
  stripe_customer_id: body.stripe_customer_id || '',
  mobile_number: String(body.mobile_number || body.mobile || '').replace(/[^0-9]/g, '').replace(/^61/, '0').slice(-10),
  customer_email: body.customer_email || body.email || '',
  prison_name: body.new_prison_name || body.prison_name || '',
  prison_state: String(body.new_prison_state || body.prison_state || '').toLowerCase(),
  threeCX_extension: body.extension || body.threeCX_extension || null,
  old_did: String(body.old_did || '').replace(/^\+/, ''),
  old_orderId: body.old_order_id || body.old_orderId || '',
  old_numberId: body.old_number_id || body.old_numberId || ''
};
return [{ json: out }];

// Order the NEW DID via the proxy (same logic as Workflow 1). Old DID details are preserved.
const helpers = this.helpers;
const PROXY_URL = 'https://workers.prisoncall.com.au/voipline-proxy';
const SECRET = $env.VOIPLINE_PROXY_SECRET;
async function voipline(path, method, jsonBody) {
  const opts = { method: 'POST', url: PROXY_URL, headers: { 'X-Proxy-Secret': SECRET, 'X-VoipLine-Path': path, 'X-VoipLine-Method': method, 'Content-Type': 'application/json' }, json: true };
  if (method === 'POST' || method === 'PUT') opts.body = jsonBody || {};
  return await helpers.httpRequest(opts);
}
const asArray = (r) => Array.isArray(r) ? r : (r && (r.data || r.results || r.numbers || r.items)) || [];
const d = $json;
let result = null;
for (const ex of d.exchanges) {
  try {
    const search = await voipline('/api/customer/pricings/countries/13?query=' + encodeURIComponent(ex.town), 'GET');
    for (const pricing of asArray(search)) {
      const pricingId = pricing.id || pricing.pricing_id;
      if (!pricingId) continue;
      try { await voipline('/api/customer/pricings/' + pricingId + '/ordering-restrictions', 'GET'); } catch (e) {}
      const numbersResp = await voipline('/api/customer/numbers/pricing/' + pricingId, 'GET');
      const numbers = asArray(numbersResp);
      if (!numbers.length) continue;
      const first = numbers[0];
      const numberId = first.id || first.number_id;
      const orderId = numbersResp.order_id || numbersResp.orderId || first.order_id;
      if (!orderId || !numberId) continue;
      await voipline('/api/customer/order/' + orderId + '/number/' + numberId + '/reserve', 'PUT', {});
      const order = await voipline('/api/customer/order/' + orderId, 'GET');
      await voipline('/api/customer/order/' + orderId + '/submit', 'POST', {});
      const did = String(first.number || first.did || (order && order.number) || '').replace(/^\+/, '');
      result = { did: did, exchange: ex.town, pricingId: pricingId, orderId: orderId, numberId: numberId };
      break;
    }
    if (result) break;
  } catch (e) {}
}
if (!result) return [{ json: { ...d, did_obtained: false, all_exhausted: true } }];
return [{ json: { ...d, ...result, did_obtained: true } }];

// MOCK: add the new DID to the EXISTING 3CX extension. Day 0 - both old + new DIDs are active.
const d = $json;
const newDid = String(d.did || '').replace(/^\+/, '');
return [{ json: { ...d, threeCX_add_did: { mocked: true, success: true, action: 'add_did_to_extension', extension: d.threeCX_extension, new_did: newDid, old_did: d.old_did, note: '15-day dual-DID overlap started - old DID stays active (NON-NEGOTIABLE)' } } }];

// Day 14 - ask the customer to confirm the new number works.
const helpers = this.helpers;
const d = $json;
const to = d.mobile_number ? ('+61' + d.mobile_number.replace(/^0/, '')) : $env.OWNER_MOBILE;
const text = 'Your new Prisoncall number ' + d.did + ' for ' + d.prison_name + ' should now be working. Please reply to confirm. Your old number will be switched off tomorrow.';
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const resp = await helpers.httpRequest({ method: 'POST', url: 'https://rest.clicksend.com/v3/sms/send', headers: { Authorization: auth, 'Content-Type': 'application/json' }, body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: to, body: text }] }, json: true });
return [{ json: { ...d, confirm_sms: resp } }];

// Day 15 (MOCK): remove the OLD DID from the 3CX extension.
const d = $json;
return [{ json: { ...d, threeCX_remove_old: { mocked: true, success: true, action: 'remove_did_from_extension', extension: d.threeCX_extension, removed_did: d.old_did } } }];

// Day 15 - release the OLD DID (2-step). Step 1 mock PBX removal already done above; step 2 VoipLine release via proxy.
const helpers = this.helpers;
const d = $json;
const PROXY = 'https://workers.prisoncall.com.au/voipline-proxy';
let release = { skipped: true, reason: 'old_orderId/old_numberId not provided in request' };
if (d.old_orderId && d.old_numberId) {
  release = await helpers.httpRequest({ method: 'POST', url: PROXY, headers: { 'X-Proxy-Secret': $env.VOIPLINE_PROXY_SECRET, 'X-VoipLine-Path': '/api/customer/order/' + d.old_orderId + '/number/' + d.old_numberId + '/release', 'X-VoipLine-Method': 'PUT', 'Content-Type': 'application/json' }, body: {}, json: true });
}
return [{ json: { ...d, old_did_release: release } }];
